import{_ as o,a as i,b as e,c as t}from"./chunks/备份成功切换读取源.D8MmJkxg.js";import{_ as p,o as d,c as n,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Nadmiarowa kopia zapasowa i przełączanie źródła odczytu","description":"","frontmatter":{},"headers":[],"relativePath":"pl-PL/Other/redundant-backup-and-read-source.md","filePath":"pl-PL/Other/redundant-backup-and-read-source.md","lastUpdated":1781962217000}'),z={name:"pl-PL/Other/redundant-backup-and-read-source.md"};function s(c,a,k,u,w,l){return d(),n("div",null,[...a[0]||(a[0]=[r('<h1 id="nadmiarowa-kopia-zapasowa-i-przełaczanie-zrodła-odczytu" tabindex="-1">Nadmiarowa kopia zapasowa i przełączanie źródła odczytu <a class="header-anchor" href="#nadmiarowa-kopia-zapasowa-i-przełaczanie-zrodła-odczytu" aria-label="Permalink to &quot;Nadmiarowa kopia zapasowa i przełączanie źródła odczytu&quot;">​</a></h1><p>Nadmiarowa kopia zapasowa zapisuje dodatkową kopię już przesłanego pliku.</p><p>Zarówno plik podstawowy, jak i plik kopii zapasowej mogą służyć jako źródła odczytu. Odwiedzający zwykle nie widzą różnicy. Zmienia się tylko kanał pamięci, który serwuje plik.</p><h2 id="co-potrafi-nadmiarowa-kopia-zapasowa" tabindex="-1">Co potrafi nadmiarowa kopia zapasowa <a class="header-anchor" href="#co-potrafi-nadmiarowa-kopia-zapasowa" aria-label="Permalink to &quot;Co potrafi nadmiarowa kopia zapasowa&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Funkcja</th><th>Opis</th></tr></thead><tbody><tr><td>Zapis dodatkowej kopii</td><td>Tworzy kopię na innym kanale uploadu, aby zmniejszyć ryzyko awarii pojedynczego kanału.</td></tr><tr><td>Przełączanie źródła odczytu</td><td>Po udanej kopii pozwala przełączać odczyt między kanałem podstawowym i zapasowym.</td></tr><tr><td>Kopia jednego pliku</td><td>Tworzy kopię z poziomu szczegółów pliku.</td></tr><tr><td>Kopia zbiorcza</td><td>Zaznacz wiele plików w panelu administracyjnym i skopiuj je razem.</td></tr><tr><td>Globalna kopia nadmiarowa</td><td>Tworzy kopie według katalogu z Innych ustawień.</td></tr></tbody></table><h2 id="wejscie-do-nadmiarowej-kopii" tabindex="-1">Wejście do nadmiarowej kopii <a class="header-anchor" href="#wejscie-do-nadmiarowej-kopii" aria-label="Permalink to &quot;Wejście do nadmiarowej kopii&quot;">​</a></h2><p>Otwórz:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Other Settings -&gt; Redundant Backup</span></span></code></pre></div><p><img src="'+o+'" alt="Nadmiarowa kopia zapasowa" loading="lazy"></p><p>To wejście najlepiej sprawdza się do dodawania kopii dla katalogu lub wielu plików naraz.</p><p>Kanał kopii można wybrać ręcznie albo wybrać automatyczne przełączanie i pozwolić ImgBed znaleźć odpowiedni kanał zapasowy.</p><h2 id="kopia-ze-szczegołow-pliku" tabindex="-1">Kopia ze szczegółów pliku <a class="header-anchor" href="#kopia-ze-szczegołow-pliku" aria-label="Permalink to &quot;Kopia ze szczegółów pliku&quot;">​</a></h2><p>Otwórz stronę szczegółów pliku w panelu administracyjnym i kliknij backup.</p><p><img src="'+i+'" alt="Kopia w szczegółach pliku" loading="lazy"></p><p>To najlepsze rozwiązanie, gdy chcesz na żądanie zabezpieczyć jeden ważny plik.</p><p>Po udanej kopii strona szczegółów pokazuje dostępne źródła odczytu.</p><h2 id="kopia-zbiorcza-z-zaznaczenia" tabindex="-1">Kopia zbiorcza z zaznaczenia <a class="header-anchor" href="#kopia-zbiorcza-z-zaznaczenia" aria-label="Permalink to &quot;Kopia zbiorcza z zaznaczenia&quot;">​</a></h2><p>W panelu administracyjnym zaznacz kilka plików i uruchom kopię zbiorczą.</p><p><img src="'+e+'" alt="Kopia zbiorcza" loading="lazy"></p><p>To dobre rozwiązanie dla grupy plików.</p><p>Kopia z zaznaczenia, kopia ze szczegółów pliku i nadmiarowa kopia z Innych ustawień używają tego samego systemu. To tylko różne punkty wejścia.</p><h2 id="przełaczanie-zrodła-odczytu-po-kopii" tabindex="-1">Przełączanie źródła odczytu po kopii <a class="header-anchor" href="#przełaczanie-zrodła-odczytu-po-kopii" aria-label="Permalink to &quot;Przełączanie źródła odczytu po kopii&quot;">​</a></h2><p>Po zakończeniu kopii strona szczegółów pozwala przełączyć źródło odczytu:</p><table tabindex="0"><thead><tr><th>Źródło odczytu</th><th>Opis</th></tr></thead><tbody><tr><td>Kanał podstawowy</td><td>Czyta z oryginalnego kanału uploadu.</td></tr><tr><td>Kanał zapasowy</td><td>Czyta z kanału, w którym znajduje się kopia nadmiarowa.</td></tr></tbody></table><p><img src="'+t+'" alt="Przełączanie źródła po kopii" loading="lazy"></p><p>Odwiedzający nie muszą wiedzieć, czy plik jest serwowany z kanału podstawowego, czy zapasowego.</p><p>Wybrane źródło staje się preferowanym źródłem dla późniejszego dostępu do pliku.</p><h2 id="kiedy-kopia-jest-pomijana" tabindex="-1">Kiedy kopia jest pomijana <a class="header-anchor" href="#kiedy-kopia-jest-pomijana" aria-label="Permalink to &quot;Kiedy kopia jest pomijana&quot;">​</a></h2><p>Poniższe przypadki są pomijane podczas tworzenia kopii. To nie są błędy.</p><table tabindex="0"><thead><tr><th>Przypadek</th><th>Dlaczego jest pomijany</th></tr></thead><tbody><tr><td>Plik ma już kopię</td><td>Plik, który ma już kopię zapasową, nie jest kopiowany ponownie.</td></tr><tr><td>Kanał podstawowy i zapasowy są takie same</td><td>Kopia ma sens tylko w innym kanale.</td></tr><tr><td>Brak użytecznego kanału zapasowego</td><td>Nie ma odpowiedniego alternatywnego kanału.</td></tr></tbody></table><p>Krótko: kopie muszą trafiać do innego kanału, a pliki już skopiowane nie zużywają ponownie miejsca.</p><h2 id="kanał-podstawowy-i-kanał-zapasowy" tabindex="-1">Kanał podstawowy i kanał zapasowy <a class="header-anchor" href="#kanał-podstawowy-i-kanał-zapasowy" aria-label="Permalink to &quot;Kanał podstawowy i kanał zapasowy&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Nazwa</th><th>Znaczenie</th></tr></thead><tbody><tr><td>Kanał podstawowy</td><td>Kanał użyty przy pierwszym uploadzie pliku.</td></tr><tr><td>Kanał zapasowy</td><td>Kanał przechowujący kopię nadmiarową.</td></tr><tr><td>Podstawowe źródło odczytu</td><td>Plik jest obecnie czytany z kanału podstawowego.</td></tr><tr><td>Zapasowe źródło odczytu</td><td>Plik jest obecnie czytany z kanału zapasowego.</td></tr></tbody></table><p>Podstawowe i zapasowe źródło odczytu zachowują się tak samo dla użytkownika.</p><p>Dopóki plik zapasowy jest dostępny, obrazy, wideo i linki pobierania działają po przełączeniu na zapasowe źródło odczytu.</p><h2 id="co-sie-dzieje-po-usunieciu-pliku" tabindex="-1">Co się dzieje po usunięciu pliku <a class="header-anchor" href="#co-sie-dzieje-po-usunieciu-pliku" aria-label="Permalink to &quot;Co się dzieje po usunięciu pliku&quot;">​</a></h2><p>Po usunięciu pliku ImgBed usuwa zarówno plik podstawowy, jak i plik zapasowy.</p>',37)])])}const j=p(z,[["render",s]]);export{h as __pageData,j as default};
